import React, { useEffect, useRef } from 'react';
import { Routes, Route } from 'react-router-dom';
import Header from './components/Header';
import SplitBanner from './components/SplitBanner';
import TheEditSection from './components/TheEditSection';
import MensEditSection from './components/MensEditSection';
import EyewearEditSection from './components/EyewearEditSection';
import CollectionPage from './pages/CollectionPage';
import { banners, womenProducts, menProducts } from './data/mockData';

function HomePage() {
  const appRef = useRef(null);

  useEffect(() => {
    const el = appRef.current;
    if (!el) return;

    const sections = Array.from(el.querySelectorAll('section'));
    let isScrolling = false;

    const onWheel = (e) => {
      e.preventDefault();
      if (isScrolling) return;

      const current = sections.reduce((prev, sec) => {
        const rect = sec.getBoundingClientRect();
        return Math.abs(rect.top) < Math.abs(prev.getBoundingClientRect().top)
          ? sec
          : prev;
      });

      const idx = sections.indexOf(current);
      const target = e.deltaY > 0 ? sections[idx + 1] : sections[idx - 1];
      if (!target) return;

      isScrolling = true;
      target.scrollIntoView({ behavior: 'smooth' });
      setTimeout(() => {
        isScrolling = false;
      }, 900);
    };

    el.addEventListener('wheel', onWheel, { passive: false });
    return () => el.removeEventListener('wheel', onWheel);
  }, []);

  return (
    <div className="app" ref={appRef}>
      <Header />
      <main>
        {/* ── 섹션 1: Womenswear 배너 ── */}
        <SplitBanner {...banners[0]} />

        {/* ── THE EDIT (여성) ── */}
        <TheEditSection products={womenProducts} />

        {/* ── 섹션 2: Menswear 배너 ── */}
        <SplitBanner {...banners[1]} />

        {/* ── THE EDIT (남성) ── */}
        <MensEditSection products={menProducts} />

        {/* ── 섹션 3: EFFECTOR × RECTO 콜라보 배너 ── */}
        <SplitBanner {...banners[2]} />

        {/* ── THE EDIT (아이웨어) ── */}
        <EyewearEditSection />
      </main>
    </div>
  );
}

function App() {
  return (
    <Routes>
      <Route path="/" element={<HomePage />} />
      <Route path="/collection/:id" element={<CollectionPage />} />
    </Routes>
  );
}

export default App;
